#include <bits/stdc++.h>
using namespace std;
using namespace std;
int a[1005],b[1005];
int dp[1005][12005];
const int N=5000;
int n,ans,dis;
int main()
{
    cin>>n;
    for(int i=1;i<=n;i++)
    {
        cin>>a[i]>>b[i];
    }
    memset(dp,0x3f,sizeof(dp));
    dp[0][N]=0;
    for(int i=1;i<=n;i++)
    {
        for(int j=-5000;j<=5000;j++)
        {
            dis=a[i]-b[i];
            dp[i][j+N]=min(dp[i-1][j-dis+N],dp[i-1][j+dis+N]+1);
        }
    }
    for(int i=0;i<=5000;i++)
    {
        ans=min(dp[n][N+i],dp[n][-i+N]);
        if(ans<=1000)
        {
            cout<<ans;
            return 0;
        }
    }
    return 0;
}
